import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.expr.NullLiteralExpr;
import com.github.javaparser.ast.expr.SimpleName;
import com.github.javaparser.ast.expr.StringLiteralExpr;
import com.github.javaparser.ast.expr.ThisExpr;
import com.github.javaparser.ast.expr.VariableDeclarationExpr;
import com.github.javaparser.ast.stmt.BlockStmt;
import com.github.javaparser.ast.stmt.IfStmt;
import com.github.javaparser.ast.stmt.ReturnStmt;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.type.PrimitiveType;
import com.github.javaparser.utils.SourceRoot;

import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public class Main {

    private static final String OUTPUT_DIR = "/workspace/qa-catalogue/src/main/java";
    private static final String PACKAGE_NAME = "de.gwdg.metadataqa.api.json";
    private static final String CLASS_NAME = "JsonBranch";

    public static void main(String[] args) {
        System.out.println("Generating missing JsonBranch class using JavaParser AST...");

        CompilationUnit cu = new CompilationUnit();
        cu.setPackageDeclaration(PACKAGE_NAME);

        ClassOrInterfaceDeclaration jsonBranchClass = cu.addClass(CLASS_NAME);
        jsonBranchClass.setPublic(true);

        FieldDeclaration parentField = jsonBranchClass.addField(
            new ClassOrInterfaceType(null, CLASS_NAME),
            "parent"
        );
        parentField.setPrivate(true);

        FieldDeclaration labelField = jsonBranchClass.addField(
            new ClassOrInterfaceType(null, "String"),
            "label"
        );
        labelField.setPrivate(true);

        FieldDeclaration jsonPathField = jsonBranchClass.addField(
            new ClassOrInterfaceType(null, "String"),
            "jsonPath"
        );
        jsonPathField.setPrivate(true);

        MethodDeclaration constructor = jsonBranchClass.addConstructor();
        constructor.setPublic(true);
        constructor.addParameter(new ClassOrInterfaceType(null, CLASS_NAME), "parent");
        constructor.addParameter(new ClassOrInterfaceType(null, "String"), "label");
        constructor.addParameter(new ClassOrInterfaceType(null, "String"), "jsonPath");

        BlockStmt constructorBody = new BlockStmt();
        constructorBody.addStatement(
            new AssignExpr(
                new FieldAccessExpr(new ThisExpr(), "parent"),
                new NameExpr("parent"),
                AssignExpr.Operator.ASSIGN
            )
        );
        constructorBody.addStatement(
            new AssignExpr(
                new FieldAccessExpr(new ThisExpr(), "label"),
                new NameExpr("label"),
                AssignExpr.Operator.ASSIGN
            )
        );
        constructorBody.addStatement(
            new AssignExpr(
                new FieldAccessExpr(new ThisExpr(), "jsonPath"),
                new NameExpr("jsonPath"),
                AssignExpr.Operator.ASSIGN
            )
        );
        constructor.setBody(constructorBody);

        MethodDeclaration getParent = jsonBranchClass.addMethod("getParent");
        getParent.setPublic(true);
        getParent.setType(new ClassOrInterfaceType(null, CLASS_NAME));
        BlockStmt getParentBody = new BlockStmt();
        getParentBody.addStatement(new ReturnStmt(new FieldAccessExpr(new ThisExpr(), "parent")));
        getParent.setBody(getParentBody);

        MethodDeclaration getLabel = jsonBranchClass.addMethod("getLabel");
        getLabel.setPublic(true);
        getLabel.setType(PrimitiveType.STRING);
        BlockStmt getLabelBody = new BlockStmt();
        getLabelBody.addStatement(new ReturnStmt(new FieldAccessExpr(new ThisExpr(), "label")));
        getLabel.setBody(getLabelBody);

        MethodDeclaration getJsonPath = jsonBranchClass.addMethod("getJsonPath");
        getJsonPath.setPublic(true);
        getJsonPath.setType(PrimitiveType.STRING);
        BlockStmt getJsonPathBody = new BlockStmt();
        getJsonPathBody.addStatement(new ReturnStmt(new FieldAccessExpr(new ThisExpr(), "jsonPath")));
        getJsonPath.setBody(getJsonPathBody);

        SourceRoot sourceRoot = new SourceRoot(Paths.get(OUTPUT_DIR));
        sourceRoot.add(PACKAGE_NAME, CLASS_NAME + ".java", cu);
        sourceRoot.saveAll();

        System.out.println("Generated: " + OUTPUT_DIR + "/" + PACKAGE_NAME.replace('.', '/') + "/" + CLASS_NAME + ".java");
        System.out.println("JsonBranch class generation complete!");
    }
}

